const text = $input.first().json.inputText || "";
const operation = $input.first().json.operation || "uppercase";

let result = "";

switch (operation) {
  case "uppercase":
    result = text.toUpperCase();
    break;
  case "lowercase":
    result = text.toLowerCase();
    break;
  case "capitalize":
    result = text
      .split(" ")
      .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
      .join(" ");
    break;
  case "reverse":
    result = text.split("").reverse().join("");
    break;
  case "word_count":
    result = `Word count: ${text.trim().split(/\s+/).length}`;
    break;
  case "remove_spaces":
    result = text.replace(/\s+/g, "");
    break;
  default:
    result = text.toUpperCase();
}

return [{ json: { result, operation, original: text } }];
